export async function markWorkspaceFailed(
  db: D1Database,
  id: string,
  message: string,
  errorCode: string | null = null
): Promise<boolean> {
  return updateWorkspaceStatus(
    db,
    id,
    'failed',
    {
      error_code: errorCode,
      error_message: message,
    },
    { ifNotDeleted: true }
  );
}
